import { createPortal } from 'react-dom'
import useToastStore from './useToastStore'
import React, { useEffect } from 'react'
import { RxCross1 } from "react-icons/rx";

export const TOAST_TYPE = {
    SUCCESS: { color: '#B5F5AE' },
    ERROR: { color: '#F78B8B' },
    WARNING: { color: '#FABB4D' }
}

function ToastRenderer() {
    const { toasts, closeToast } = useToastStore((state) => state)
    const toastRoot = document.getElementById('toast-root')
    if (!toastRoot) return null

    return createPortal(
        toasts.map(({ id, message, type }, idx) => <div className='toast-container' style={{ top: `${50 + idx * 50}px` }} key={id} >
            <Toast onClose={() => closeToast(id)} content={message} type={type} />
        </div >)
        , toastRoot)
}

export default ToastRenderer


function Toast({ content, timerDelay = 3000, type, onClose }) {
    function getBackground(type) {
        let color = 'grey'
        switch (type) {
            case TOAST_TYPE.SUCCESS: color = '#B5F5AE'
                break
            case TOAST_TYPE.ERROR: color = '#F78B8B'
                break
            case TOAST_TYPE.WARNING: color = '#FABB4D'
                break
        }
        return color
    }
    function handleClose() {
        onClose()
    }
    useEffect(() => {
        setTimeout(() => {
            onClose()
        }, [timerDelay])
    })
    return (
        <div style={{ backgroundColor: getBackground(type) }} className='toast'>
            <div>{content}</div>
            <button className='close-btn' onClick={handleClose}><RxCross1 /></button>
        </div>
    )
}
